urlset:
{% for page in load_pages("blog") -%}

  {{ base_url(path_parent(page.path)) | safe }}/
  {% if page.frontmatter.date is string -%}
    {{ page.frontmatter.date | datetime(format="iso") }}
  {%- else -%}
    {{ page.metadata.modified | datetime(format="iso") }}
  {%- endif %}

{%- endfor %}
